Here is the updated `components/ChapterPage.tsx` file. The primary change is in the `togglePlayPause` function to correctly handle the `AbortError` that occurs when `play()` is interrupted by `pause()`. I have also switched to checking `audioRef.current.paused` as the source of truth for toggling playback, rather than relying on the `isPlaying` state which can be momentarily out of sync.

# Updated files:

## components/ChapterPage.tsx

- Updated `togglePlayPause` to handle `AbortError` from `play()` gracefully.
- Removed explicit `setIsPlaying` in `togglePlayPause` to let `onPlay` and `onPause` event handlers manage the state consistently.
- Switched logic to check `!audio.paused` instead of `isPlaying` state to prevent race conditions.

```tsx
import React, { useState, useEffect, useRef, useCallback } from 'react';
import type { Chapter } from '../types.ts';
import LearnTab from './LearnTab.tsx';
import SummaryTab from './SummaryTab.tsx';
import QATab from './QATab.tsx';
import AskTab from './AskTab.tsx';
import { ArrowLeft, BookOpen, Layers, HelpCircle, MessageSquare, Play, Pause, ExternalLink } from './Icons.tsx';

interface ChapterPageProps {
  chapter: Chapter;
  onGoHome: () => void;
  onUpdateChapterScore: (chapterId: number, score: number, totalQuestions: number) => void;
}

type Tab = 'learn' | 'summary' | 'qa' | 'ask';

const getGoogleDriveEmbed = (url: string) => {
  if (!url) return null;
  const patterns = [
    /\/file\/d\/([a-zA-Z0-9_-]+)/,
    /id=([a-zA-Z0-9_-]+)/
  ];

  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match && match[1]) {
      return `https://drive.google.com/file/d/${match[1]}/preview`;
    }
  }
  return null;
};

const ChapterPage: React.FC<ChapterPageProps> = ({ chapter, onGoHome, onUpdateChapterScore }) => {
  const [activeTab, setActiveTab] = useState<Tab>('learn');
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [audioError, setAudioError] = useState(false);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [chapter.id]);

  useEffect(() => {
    if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.currentTime = 0;
    }
    setIsPlaying(false);
    setCurrentTime(0);
    setDuration(0);
    setAudioError(false);
  }, [chapter.id]);

  const togglePlayPause = useCallback(() => {
    const audio = audioRef.current;
    if (audio && !audioError) {
      if (!audio.paused) {
        audio.pause();
      } else {
        const playPromise = audio.play();
        if (playPromise !== undefined) {
            playPromise.catch(e => {
                // Ignore AbortError which happens if pause() is called while play() is pending
                if (e.name !== 'AbortError') {
                    console.error("Play error:", e);
                    setAudioError(true);
                }
            });
        }
      }
    }
  }, [audioError]);

  const handleTimeUpdate = useCallback(() => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
    }
  }, []);

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newTime = parseFloat(e.target.value);
    if (audioRef.current) {
      audioRef.current.currentTime = newTime;
    }
    setCurrentTime(newTime);
  };

  const handleLoadedMetadata = useCallback(() => {
    if (audioRef.current) {
      setDuration(audioRef.current.duration);
      setAudioError(false);
    }
  }, []);

  const handleAudioError = useCallback(() => {
      // Only set error if no duration (meaning load failed completely)
      // or network state implies error.
      // Sometimes onError fires for minor things.
      if (audioRef.current && audioRef.current.error) {
          console.error("Audio Object Error:", audioRef.current.error);
          setAudioError(true);
          setIsPlaying(false);
      }
  }, []);

  const formatTime = (seconds: number) => {
    const minutes = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${minutes}:${secs < 10 ? '0' : ''}${secs}`;
  };

  const tabs: { id: Tab; name: string; icon: React.ReactNode }[] = [
    { id: 'learn', name: 'Learn', icon: <BookOpen className="h-4 w-4" /> },
    { id: 'summary', name: 'Summary', icon: <Layers className="h-4 w-4" /> },
    { id: 'qa', name: 'Quiz', icon: <HelpCircle className="h-4 w-4" /> },
    { id: 'ask', name: 'Ask AI', icon: <MessageSquare className="h-4 w-4" /> },
  ];

  const isDriveFolder = chapter.malayalamAudioUrl?.includes('/folders/') || (chapter.malayalamAudioUrl?.includes('drive.google.com') && !chapter.malayalamAudioUrl.includes('file/d'));
  const driveEmbedUrl = !isDriveFolder && chapter.malayalamAudioUrl ? getGoogleDriveEmbed(chapter.malayalamAudioUrl) : null;

  return (
    <div className="animate-fade-in max-w-5xl mx-auto pb-24">

      {/* Header */}
      <div className="mb-10">
        <button
          onClick={onGoHome}
          className="group flex items-center gap-2 text-text-muted hover:text-primary transition-colors text-sm font-bold mb-8 bg-surface/50 w-fit px-4 py-2 rounded-full border border-border backdrop-blur-sm"
        >
          <ArrowLeft className="h-4 w-4 group-hover:-translate-x-1 transition-transform" />
          <span>Back to Chapters</span>
        </button>

        <div className="flex items-center gap-2 text-primary font-bold text-xs uppercase tracking-widest mb-3">
             <span className="w-2 h-2 rounded-full bg-primary"></span>
             Chapter {chapter.id}
        </div>
        <h1 className="text-3xl sm:text-5xl font-black text-text-main tracking-tight mb-4 leading-tight">
             {chapter.title}
        </h1>
        <p className="text-lg text-text-muted font-medium leading-relaxed max-w-3xl">
             {chapter.description}
        </p>
      </div>

      {/* Sleek Audio Player */}
      {chapter.malayalamAudioUrl && (
        <div className="relative mb-12 group">
          <div className="absolute inset-0 bg-gradient-to-r from-primary to-secondary rounded-3xl opacity-10 blur-xl group-hover:opacity-15 transition-opacity"></div>
          <div className="relative bg-surface/80 dark:bg-slate-800/80 backdrop-blur-xl border-2 border-white/60 dark:border-white/30 rounded-3xl p-6 shadow-glass flex flex-col md:flex-row items-center gap-6">

             <div className="flex items-center gap-4 w-full md:w-auto">
                 <button 
                    onClick={togglePlayPause}
                    disabled={audioError}
                    className={`w-14 h-14 rounded-full flex items-center justify-center text-white shadow-lg shadow-primary/30 transition-all transform hover:scale-105 active:scale-95 shrink-0 ${audioError ? 'bg-red-500 cursor-not-allowed' : 'bg-gradient-to-br from-primary to-secondary'}`}
                 >
                    {isPlaying ? <Pause className="w-6 h-6" /> : <Play className="w-6 h-6 pl-1" />}
                 </button>
                 <div className="md:hidden flex items-center gap-2">
                    <div>
                        <h3 className="font-bold text-text-main">Audio Lesson</h3>
                        <p className="text-xs text-text-muted">Listen to the summary</p>
                    </div>
                    {/* Mobile Visualizer */}
                    <div className="flex items-center gap-0.5 h-6 ml-auto">
                        {[...Array(5)].map((_, i) => (
                            <div 
                                key={i} 
                                className="w-1 bg-primary/80 rounded-full" 
                                style={{ 
                                    height: isPlaying ? '100%' : '20%', 
                                    animation: isPlaying ? `equalizer 0.8s ease-in-out infinite alternate` : 'none',
                                    animationDelay: `${i * 0.1}s` 
                                }}
                            ></div>
                        ))}
                    </div>
                 </div>
             </div>

             <div className="flex-1 w-full space-y-2">
                 <div className="hidden md:flex justify-between items-end">
                    <div className="flex items-center gap-4">
                        <div>
                            <h3 className="font-bold text-text-main text-lg">Malayalam Audio Lesson</h3>
                            <p className="text-sm text-text-muted">Clear concepts in your language</p>
                        </div>
                        {/* Desktop Visualizer */}
                        <div className="flex items-end gap-1 h-6 ml-2 pb-1">
                            {[...Array(12)].map((_, i) => (
                                <div 
                                    key={i} 
                                    className="w-1 bg-gradient-to-t from-primary to-secondary rounded-t-sm opacity-80" 
                                    style={{ 
                                        height: isPlaying ? '100%' : '20%', 
                                        animation: isPlaying ? `equalizer 0.6s ease-in-out infinite alternate` : 'none',
                                        animationDelay: `${i * 0.05}s` 
                                    }}
                                ></div>
                            ))}
                        </div>
                    </div>
                    {audioError && <span className="text-xs text-red-500 font-bold bg-red-50 px-2 py-1 rounded">Playback Error</span>}
                 </div>

                 {!audioError && (
                     <div className="flex items-center gap-4 w-full">
                        <span className="text-xs font-bold text-text-muted w-10 text-right tabular-nums">{formatTime(currentTime)}</span>

                        <div className="relative flex-1 h-2 group/slider flex items-center">
                             {/* Background Track */}
                             <div className="absolute inset-0 bg-border/50 rounded-full"></div>

                             {/* Active Progress */}
                             <div 
                                className="absolute inset-y-0 left-0 bg-gradient-to-r from-primary to-secondary rounded-full pointer-events-none" 
                                style={{ width: `${duration ? (currentTime / duration) * 100 : 0}%` }}
                             ></div>

                             {/* Interactive Range Input */}
                             <input 
                                type="range" 
                                min="0" 
                                max={duration || 0} 
                                step="0.1"
                                value={currentTime}
                                onChange={handleSeek}
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10"
                                aria-label="Seek audio"
                             />

                             {/* Thumb Knob (Visual only, appears on hover) */}
                             <div 
                                className="absolute h-4 w-4 bg-white border-2 border-primary rounded-full shadow-md pointer-events-none opacity-0 group-hover/slider:opacity-100 transition-opacity duration-200"
                                style={{ 
                                    left: `${duration ? (currentTime / duration) * 100 : 0}%`, 
                                    transform: 'translateX(-50%)' 
                                }} 
                             ></div>
                        </div>

                        <span className="text-xs font-bold text-text-muted w-10 tabular-nums">{formatTime(duration)}</span>
                     </div>
                 )}
                 <audio 
                    ref={audioRef} 
                    src={chapter.malayalamAudioUrl} 
                    onPlay={() => setIsPlaying(true)}
                    onPause={() => setIsPlaying(false)}
                    onEnded={() => setIsPlaying(false)}
                    onTimeUpdate={handleTimeUpdate}
                    onLoadedMetadata={handleLoadedMetadata}
                    onError={handleAudioError}
                    preload="metadata" 
                />
             </div>

             {/* External Link Option */}
             <a 
                href={chapter.malayalamAudioUrl}
                target="_blank" 
                rel="noreferrer"
                className="p-3 rounded-xl hover:bg-surface border border-transparent hover:border-border transition-all text-text-muted hover:text-primary"
                title="Open Externally"
             >
                <ExternalLink className="w-5 h-5" />
             </a>
          </div>
        </div>
      )}

      {/* Segmented Control Tabs */}
      <div className="mb-10 flex justify-center">
        <div className="inline-flex p-1.5 bg-surface/60 dark:bg-slate-800/60 backdrop-blur-md rounded-2xl border border-border shadow-sm">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold text-sm transition-all duration-300 ${
                activeTab === tab.id
                  ? 'bg-white dark:bg-slate-700 text-primary shadow-md'
                  : 'text-text-muted hover:text-text-main hover:bg-white/40 dark:hover:bg-slate-600/40'
              }`}
            >
              {tab.icon}
              <span className="hidden sm:inline">{tab.name}</span>
            </button>
          ))}
        </div>
      </div>

      {/* Content Area */}
      <div className="glass-panel p-6 sm:p-10 rounded-[2.5rem] min-h-[500px] animate-slide-up">
        {activeTab === 'learn' && <LearnTab content={chapter.content.explanation} memoryTechniques={chapter.content.memoryTechniques} examTips={chapter.content.examTips} />}
        {activeTab === 'summary' && <SummaryTab summary={chapter.content.summary} />}
        {activeTab === 'qa' && <QATab questions={chapter.content.questions} chapterId={chapter.id} onUpdateScore={onUpdateChapterScore} />}
        {activeTab === 'ask' && <AskTab chapter={chapter} />}
      </div>

    </div>
  );
};

export default ChapterPage;
